package ru.memearena.media.api; import ru.memearena.media.domain.MediaAsset; import java.time.Instant; import java.util.UUID; public record MediaUploadResponse(UUID id,String contentType,long sizeBytes,String contentUrl,boolean duplicateDetected,Instant createdAt){ public static MediaUploadResponse of(MediaAsset a,boolean d){return new MediaUploadResponse(a.getId(),a.getContentType(),a.getSizeBytes(),"/api/v1/media/"+a.getId()+"/content",d,a.getCreatedAt());}}
